style.css:
@import url("https://fonts.googleapis.com/css2?family=Inter:opsz@14..32&family=Raleway:ital,wght@0,100..900;1,100..900&display=swap");

* {
  box-sizing: border-box;
  padding: 0;
  margin: 0;
}

body {
  font-family: "Raleway", sans-serif;
  display: flex;
  justify-content: center;
  background-color: #dddddd;
  margin: 0;
  color: #222222;
  padding-top: 2rem;
}

.user-card {
  width: 400px;
  height: 550px;
  border: 12px solid #fff;
  border-radius: 40px;
  overflow: hidden;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
  position: relative;
  background: #000; /* fallback */
}

.user-card::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  backdrop-filter: blur(30px) saturate(220%);
  background: linear-gradient(
    to bottom,
    rgba(255, 255, 255, 0) 0%,
    rgba(255, 255, 255, 0.01) 30%,
    rgba(255, 255, 255, 0.03) 50%,
    rgba(255, 255, 255, 0.08) 70%,
    rgba(255, 255, 255, 0.15) 85%,
    rgba(255, 255, 255, 0.2) 100%
  );
  mask-image: linear-gradient(
    to bottom,
    transparent 0%,
    rgba(0, 0, 0, 0.1) 40%,
    rgba(0, 0, 0, 0.5) 55%,
    black 75%
  );
}

.user-card__media {
  margin: 0;
}
.user-card__avatar {
  display: block;
  width: 100%;
  height: auto;
}

.user-card__body {
  position: absolute;
  bottom: 20px;
  left: 20px;
  right: 20px;
  color: #ddd;
  z-index: 1;
}

.user-card__header {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-bottom: 8px;
}
.user-card__name {
  font-size: 1.6rem;
  line-height: 1.1;
  font-weight: 600;
}
.user-card__badge {
  width: 24px;
  height: 24px;
}
.user-card__description {
  font-size: 1.2rem;
  letter-spacing: 1px;
}

.user-card__footer {
  margin-top: 2rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.user-card__stats {
  display: flex;
  gap: 16px;
}

.user-card__stat {
  display: flex;
  align-items: center;
  font-family: "Inter", sans-serif;
  gap: 4px;
  font-size: 0.975rem;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
  background-color: rgba(255, 255, 255, 0.2);
  border-radius: 40px;
  padding: 0.3rem 0.71rem;
  color: #222222;
}
.user-card__stat-value {
  font-weight: 600;
}

.user-card__actions {
  display: flex;
  align-items: center;
}
.user-card__follow-btn {
  background-color: rgba(255, 255, 255, 0.2);
  color: #222222;
  border-radius: 40px;
  font-family: inherit;
  font-size: 1.2rem;
  display: flex;
  line-height: 1;
  align-items: center;
  gap: 4px;
  padding: 0.5rem 0.8rem;
  border: none;
  cursor: pointer;
  font-weight: 600;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
  transition: background 0.2s ease, transform 0.3s ease;
}
.user-card__follow-btn:hover {
  background-color: rgba(255, 255, 255, 0.4);
  transform: scale(1.1);
}
.user-card__follow-btn:active {
  transform: translateY(1px);
}
.user-card__follow-btn:focus-visible {
  outline: 2px solid #333;
  outline-offset: 3px;
}
.user-card__follow-btn svg {
  width: 32px;
  height: 32px;
}

@media (max-width: 480px) {
  .user-card {
    width: 320px;
    height: 520px;
    border-width: 10px;
  }
  .user-card__name {
    font-size: 1.4rem;
  }
  .user-card__description {
    font-size: 1.05rem;
  }
  .user-card__follow-btn {
    font-size: 1.05rem;
  }
}
